export default function codeExcerpt(source, line, options = {}) {
  const around = options.around ?? 2;
  const lines = String(source).split(/\r?\n/);
  const start = Math.max(1, Number(line) - around);
  const end = Math.min(lines.length, Number(line) + around);
  const result = [];
  for (let current = start; current <= end; current++) {
    result.push({ line: current, value: lines[current - 1] ?? '' });
  }
  return result;
}
